const response = $input.first().json.content.parts[1].text;
// تنظيف النص من أي علامات زائدة عشان يتحول لـ JSON
const cleanJson = response.replace(/```json/g, '').replace(/```/g, '').trim();
const data = JSON.parse(cleanJson);

if (data.ignore === true) {
  return [{ json: { ignore: true } }];
}

// تحويل كل معاملة لسطر منفصل عشان يترحلوا للجدول
return data.rows.map(row => {
  return {
    json: {
      ignore: false,
      amount: row.amount,
      type: row.type,
      date: row.date,
      time: row.time
    }
  };
});
